#!/usr/bin/perl\nuse strict;\nuse warnings;\n\n# Main scheduling algorithm for exam scheduler\n\nsub schedule_exams {\n    my (@exams) = @_;\n    my %schedule;\n\n    foreach my $exam (@exams) {\n        # Simple scheduling logic; adjust as needed\n        my $slot = find_slot($exam, \\%schedule);\n        $schedule{$slot} = $exam if defined $slot;\n    }\n\n    return %schedule;\n}\n\nsub find_slot {\n    my ($exam, $schedule) = @_;\n\n    # Placeholder for logic to find a free slot for the exam\n    # In this example, we just return a random time slot\n    my $time_slot = "2026-04-20 10:00:00"; # Example slot\n    return $time_slot;\n}\n\n# Example usage\nmy @exams = ('Math', 'Physics', 'Chemistry');\nmy %exam_schedule = schedule_exams(@exams);\n\nforeach my $time (keys %exam_schedule) {\n    print "Exam: $exam_schedule{$time} at $time\n";\n}